mapper.select:
SELECT 
FROM work_record_transfer
WHERE from_user_id = #{fromUserId}
ORDER BY create_time DESC, id DESC
LIMIT #{limit}

mapper.update:
UPDATE work_record_transfer
SET status = #{toStatus},
    reply = #{reply},
    handle_time = NOW()
WHERE id = #{id}
  AND to_user_id = #{toUserId}
  AND from_user_id = #{fromUserId}
  AND status = #{fromStatus}
